// src/App.js - Updated with Common Components

import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import './App.css';

// Import Common Components và Styles
import './components/common/styles.css';
import {
  Header,
  Sidebar,
  Footer,
  Loading,
  ToastProvider,
  useToast,
  FullscreenLoading,
  ConfirmDialog,
  useConfirmDialog
} from './components/common';

// Import Charts
import Charts from './components/charts';

// Context Providers
import { AuthProvider, useAuth } from './context/AuthContext';
import { WarehouseProvider } from './context/WarehouseContext';
import { NotificationProvider } from './context/NotificationContext';
import { SettingsProvider } from './context/SettingsContext';
import { PermissionProvider } from './context/PermissionContext';

// Components
import ProtectedRoute from './components/auth/ProtectedRoute';

// Auth Pages
import Login from './pages/Auth/Login';
import ForgotPassword from './pages/Auth/ForgotPassword';
import ChangePassword from './pages/Auth/ChangePassword';

// Main Pages
import Dashboard from './pages/Dashboard/Dashboard';

// Module 1: Nhập Hàng
import NhapHang from './pages/NhapHang/NhapHang';

// Module 2: Tạo Đơn
import TaoDon from './pages/TaoDon/TaoDon';
import QuanLyCuaHang from './pages/TaoDon/QuanLyCuaHang';
import QuanLySanPham from './pages/TaoDon/QuanLySanPham';

// Module 3: Xuất Hàng
import XuatHang from './pages/XuatHang/XuatHang';

// Module 4: Quản Lý Kho
import QuanLyKho from './pages/QuanLyKho/QuanLyKho';
import QuanLyViTri from './pages/QuanLyKho/QuanLyViTri';
import QuanLyHangHoa from './pages/QuanLyKho/QuanLyHangHoa';
import TinhTrangHang from './pages/QuanLyKho/TinhTrangHang';
import KiemKe from './pages/QuanLyKho/KiemKe';
import BaoTri from './pages/QuanLyKho/BaoTri';

// Module 5: Kiểm Tra Giao Hàng
import KiemTraGiaoHang from './pages/KiemTraGiaoHang/KiemTraGiaoHang';

// Reports & Analytics
import BaoCao from './pages/BaoCao/BaoCao';

// Settings & Admin
import Settings from './pages/Settings/Settings';
import AdminDashboard from './pages/Admin/AdminDashboard';
import UserManagement from './pages/Admin/UserManagement';
import RoleManagement from './pages/Admin/RoleManagement';

// Error Pages
import NotFound from './pages/Error/NotFound';
import Unauthorized from './pages/Error/Unauthorized';

// Services
import { checkSystemHealth } from './services/api';

// Navigation Configuration
import { 
  warehouseNavigation, 
  warehouseUserMenu,
  warehouseSidebarNavigation 
} from './components/common';

// Layout Component with Common Components
const AppLayout = ({ children }) => {
  const { user } = useAuth();
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [systemHealth, setSystemHealth] = useState(null);
  const toast = useToast();
  const { showConfirm, ConfirmDialog } = useConfirmDialog();

  useEffect(() => {
    // Check system health on app load
    const checkHealth = async () => {
      try {
        const health = await checkSystemHealth();
        setSystemHealth(health);

        // Show toast notification for system status
        if (health.status === 'error') {
          toast.error(`Hệ thống gặp sự cố: ${health.message}`);
        } else if (health.status === 'warning') {
          toast.warning(`Cảnh báo hệ thống: ${health.message}`);
        }
      } catch (error) {
        console.error('System health check failed:', error);
        setSystemHealth({ status: 'error', message: 'Không thể kết nối hệ thống' });
        toast.error('Không thể kiểm tra trạng thái hệ thống');
      }
    };

    if (user) {
      checkHealth();
      // Check health every 5 minutes
      const interval = setInterval(checkHealth, 5 * 60 * 1000);
      return () => clearInterval(interval);
    }
  }, [user, toast]);

  // Handle user menu actions
  const handleUserMenuClick = async (action) => {
    switch (action.action) {
      case 'profile':
        // Navigate to profile
        break;

      case 'settings':
        // Navigate to settings
        break;

      case 'logout':
        const confirmed = await showConfirm({
          title: 'Đăng xuất',
          message: 'Bạn có chắc chắn muốn đăng xuất khỏi hệ thống?',
          type: 'warning',
          confirmText: 'Đăng xuất',
          cancelText: 'Hủy'
        });

        if (confirmed) {
          // Perform logout
          toast.success('Đăng xuất thành công');
        }
        break;

      default:
        console.log('Unknown action:', action);
    }
  };

  // Handle navigation click
  const handleNavigationClick = (item) => {
    console.log('Navigate to:', item.path);
  };

  // Handle search
  const handleSearch = (query) => {
    console.log('Search:', query);
    toast.info(`Tìm kiếm: ${query}`);
  };

  // Get notifications for header
  const notifications = [
    { id: 1, title: 'Đơn hàng mới', message: 'Có 5 đơn hàng mới cần xử lý', read: false },
    { id: 2, title: 'Hàng sắp hết', message: 'Sản phẩm ABC sắp hết hàng', read: false },
    { id: 3, title: 'Báo cáo tuần', message: 'Báo cáo tuần đã sẵn sàng', read: true }
  ];

  return (
    <div className={`app-layout ${sidebarCollapsed ? 'sidebar-collapsed' : ''}`}>
      {/* System Health Banner */}
      {systemHealth?.status === 'error' && (
        <div className="system-health-banner error">
          <span className="system-health-icon">⚠️</span>
          <span>Hệ thống đang gặp sự cố: {systemHealth.message}</span>
          <button 
            onClick={() => window.location.reload()}
            className="system-health-retry"
          >
            Thử lại
          </button>
        </div>
      )}

      {/* Header with Common Component */}
      <Header 
        title="Warehouse System"
        subtitle="Management"
        navigation={warehouseNavigation}
        user={user}
        userMenu={warehouseUserMenu}
        notifications={notifications}
        onSearch={handleSearch}
        onNavigationClick={handleNavigationClick}
        onUserMenuClick={handleUserMenuClick}
        showSearch={true}
        actions={[
          {
            icon: '🔔',
            title: 'Thông báo',
            onClick: () => toast.info('Hiển thị thông báo'),
            badge: { count: notifications.filter(n => !n.read).length }
          },
          {
            icon: '❓',
            title: 'Trợ giúp',
            onClick: () => toast.info('Hiển thị trợ giúp')
          }
        ]}
      />

      {/* Main Content */}
      <div className="app-content">
        {/* Sidebar with Common Component */}
        <Sidebar 
          title="WMS"
          subtitle="Management"
          navigation={warehouseSidebarNavigation}
          user={user}
          collapsed={sidebarCollapsed}
          open={sidebarOpen}
          onToggle={() => setSidebarCollapsed(!sidebarCollapsed)}
          onClose={() => setSidebarOpen(false)}
          onNavigationClick={handleNavigationClick}
          onUserClick={() => console.log('User profile clicked')}
          breakpoint={1024}
        />

        {/* Page Content */}
        <main className="main-content">
          <div className="content-wrapper">
            {children}
          </div>

          {/* Footer with Common Component */}
          <Footer 
            title="Warehouse System"
            subtitle="Management"
            description="Hệ thống quản lý kho hiện đại với công nghệ AI và IoT"
            sections={[
              {
                title: 'Sản phẩm',
                links: [
                  { label: 'Quản lý kho', url: '/quan-ly-kho' },
                  { label: 'Xuất nhập hàng', url: '/nhap-hang' },
                  { label: 'Báo cáo', url: '/bao-cao' }
                ]
              },
              {
                title: 'Hỗ trợ',
                links: [
                  { label: 'Trung tâm trợ giúp', url: '/help' },
                  { label: 'Liên hệ', url: '/contact' }
                ]
              }
            ]}
            socialLinks={[
              { platform: 'Facebook', icon: '📘', url: '#' },
              { platform: 'Twitter', icon: '🐦', url: '#' }
            ]}
            copyright="© 2025 Warehouse Management System. All rights reserved."
            legalLinks={[
              { label: 'Điều khoản', url: '/terms' },
              { label: 'Bảo mật', url: '/privacy' }
            ]}
            version={{
              number: '1.0.0',
              date: '2025-01-01',
              status: 'stable'
            }}
            variant="default"
          />
        </main>
      </div>

      {/* Confirm Dialog */}
      <ConfirmDialog />
    </div>
  );
};

// Main App Component with Toast Provider
const App = () => {
  const [appLoading, setAppLoading] = useState(true);
  const [appError, setAppError] = useState(null);

  useEffect(() => {
    // Initialize app
    const initializeApp = async () => {
      try {
        // Load app configuration
        await new Promise(resolve => setTimeout(resolve, 1500)); // Simulate loading

        // Initialize theme
        const savedTheme = localStorage.getItem('theme');
        const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
        const initialTheme = savedTheme || (prefersDark ? 'dark' : 'light');
        document.documentElement.setAttribute('data-theme', initialTheme);

        setAppLoading(false);
      } catch (error) {
        console.error('App initialization failed:', error);
        setAppError(error.message);
        setAppLoading(false);
      }
    };

    initializeApp();
  }, []);

  if (appLoading) {
    return (
      <FullscreenLoading
        show={true}
        type="gradient"
        text="Đang khởi tạo hệ thống..."
        subtitle="Vui lòng đợi trong giây lát"
        logo={
          <div style={{ 
            width: '64px', 
            height: '64px', 
            background: 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)',
            borderRadius: '16px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '28px',
            color: 'white',
            marginBottom: '24px'
          }}>
            🏭
          </div>
        }
      />
    );
  }

  if (appError) {
    return (
      <div className="app-error">
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          minHeight: '100vh',
          padding: '20px',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '64px', marginBottom: '16px' }}>⚠️</div>
          <h2>Không thể khởi tạo ứng dụng</h2>
          <p>{appError}</p>
          <button 
            onClick={() => window.location.reload()}
            style={{
              padding: '12px 24px',
              borderRadius: '8px',
              border: 'none',
              background: '#3b82f6',
              color: 'white',
              cursor: 'pointer',
              marginTop: '16px'
            }}
          >
            Thử lại
          </button>
        </div>
      </div>
    );
  }

  return (
    <AuthProvider>
      <PermissionProvider>
        <SettingsProvider>
          <WarehouseProvider>
            <NotificationProvider>
              <ToastProvider position="top-right" maxToasts={5}>
                <Router>
                  <div className="App">
                    <Routes>
                      {/* Public Routes */}
                      <Route path="/login" element={<PublicRoute><Login /></PublicRoute>} />
                      <Route path="/forgot-password" element={<PublicRoute><ForgotPassword /></PublicRoute>} />

                      {/* Protected Routes */}
                      <Route path="/" element={
                        <ProtectedRoute>
                          <AppLayout>
                            <Navigate to="/dashboard" replace />
