                          <AppLayout>
                            <KiemTraGiaoHang />
                          </AppLayout>
                        </ProtectedRoute>
                      } />

                      {/* Reports */}
                      <Route path="/bao-cao/*" element={
                        <ProtectedRoute module="bao_cao" action="view">
                          <AppLayout>
                            <BaoCao />
                          </AppLayout>
                        </ProtectedRoute>
                      } />

                      {/* Settings */}
                      <Route path="/settings/*" element={
                        <ProtectedRoute>
                          <AppLayout>
                            <Settings />
